import json
import os
import functions_framework
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
from datetime import datetime


# Configuration - set these via environment variables or modify defaults
PROJECT_ID = os.environ.get("GCP_PROJECT_ID", "your-project-id")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "file-processing-topic")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "processed_files")
PROCESSED_BUCKET = os.environ.get("PROCESSED_BUCKET", "your-processed-bucket")


def get_storage_client():
    """Initialize Cloud Storage client."""
    return storage.Client(project=PROJECT_ID)


def get_firestore_client():
    """Initialize Firestore client."""
    return firestore.Client(project=PROJECT_ID)


def get_pubsub_publisher():
    """Initialize Pub/Sub publisher client."""
    return pubsub_v1.PublisherClient()


def read_file_from_gcs(bucket_name, file_name):
    """
    Read a file from Cloud Storage and return its contents and metadata.

    WARNING: This function uses a service account with Storage Admin permissions,
    which grants full control over all Storage resources. For production, use
    the principle of least privilege and scope down to specific buckets/objects.
    """
    client = get_storage_client()
    bucket = client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    if not blob.exists():
        raise FileNotFoundError(f"File {file_name} not found in bucket {bucket_name}")

    content = blob.download_as_text()
    metadata = {
        "name": blob.name,
        "bucket": blob.bucket.name,
        "size": blob.size,
        "content_type": blob.content_type,
        "created": blob.time_created.isoformat() if blob.time_created else None,
        "updated": blob.updated.isoformat() if blob.updated else None,
        "md5_hash": blob.md5_hash,
    }

    return content, metadata


def process_file_content(content, metadata):
    """
    Process the file content. This is a placeholder for your business logic.
    Modify this function based on your actual processing needs.
    """
    lines = content.strip().split("\n") if content.strip() else []
    word_count = sum(len(line.split()) for line in lines)
    char_count = len(content)

    processed_data = {
        "file_name": metadata["name"],
        "bucket": metadata["bucket"],
        "file_size_bytes": metadata["size"],
        "content_type": metadata["content_type"],
        "line_count": len(lines),
        "word_count": word_count,
        "character_count": char_count,
        "processing_timestamp": datetime.utcnow().isoformat(),
        "status": "processed",
        "original_metadata": metadata,
    }

    # Add first few lines as preview
    preview_lines = lines[:5] if lines else []
    processed_data["content_preview"] = preview_lines

    return processed_data


def write_to_firestore(processed_data):
    """
    Write processed data to Firestore.

    WARNING: This function uses a service account with Datastore User permissions,
    which grants read/write access to ALL Firestore/Datastore entities.
    For production, use Firestore Security Rules and more restrictive IAM roles.
    """
    client = get_firestore_client()
    collection_ref = client.collection(FIRESTORE_COLLECTION)

    # Use file name (sanitized) as document ID for idempotency
    doc_id = processed_data["file_name"].replace("/", "_").replace(".", "_")

    doc_ref = collection_ref.document(doc_id)
    doc_ref.set(processed_data, merge=True)

    print(f"Written document {doc_id} to Firestore collection {FIRESTORE_COLLECTION}")
    return doc_id


def publish_to_pubsub(processed_data, doc_id):
    """
    Publish a message to Pub/Sub for downstream consumers.

    WARNING: This function uses a service account with Pub/Sub Publisher permissions,
    which allows publishing to ANY topic in the project. For production,
    restrict to specific topics using IAM conditions or topic-level permissions.
    """
    publisher = get_pubsub_publisher()
    topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)

    message_data = {
        "event_type": "file_processed",
        "document_id": doc_id,
        "file_name": processed_data["file_name"],
        "bucket": processed_data["bucket"],
        "processing_timestamp": processed_data["processing_timestamp"],
        "status": processed_data["status"],
        "summary": {
            "line_count": processed_data["line_count"],
            "word_count": processed_data["word_count"],
            "character_count": processed_data["character_count"],
        },
    }

    message_bytes = json.dumps(message_data).encode("utf-8")

    # Publish with attributes for filtering
    future = publisher.publish(
        topic_path,
        data=message_bytes,
        source="file-processor-function",
        file_name=processed_data["file_name"],
        status=processed_data["status"],
    )

    message_id = future.result()
    print(f"Published message {message_id} to topic {PUBSUB_TOPIC}")
    return message_id


def copy_to_processed_bucket(bucket_name, file_name):
    """
    Optionally copy the processed file to a separate bucket.

    WARNING: Storage Admin permission allows copying/moving files across
    ALL buckets in the project. Scope down for production use.
    """
    client = get_storage_client()
    source_bucket = client.bucket(bucket_name)
    source_blob = source_bucket.blob(file_name)
    destination_bucket = client.bucket(PROCESSED_BUCKET)

    source_bucket.copy_blob(
        source_blob,
        destination_bucket,
        new_name=f"processed/{file_name}",
    )
    print(f"Copied {file_name} to {PROCESSED_BUCKET}/processed/{file_name}")


@functions_framework.cloud_event
def process_gcs_file(cloud_event):
    """
    Cloud Function triggered by a Cloud Storage event (finalize/create).

    This function:
    1. Reads the uploaded file from Cloud Storage
    2. Processes the file content
    3. Writes results to Firestore
    4. Publishes a notification to Pub/Sub
    5. Optionally copies the file to a processed bucket

    SECURITY WARNING:
    This function's service account has broad permissions for MVP development:
    - roles/storage.admin: Full control over ALL Cloud Storage resources
    - roles/datastore.user: Read/write access to ALL Firestore/Datastore data
    - roles/pubsub.publisher: Can publish to ANY Pub/Sub topic

    FOR PRODUCTION, apply the principle of least privilege:
    - Use roles/storage.objectViewer on specific buckets instead of storage.admin
    - Use custom IAM roles with only needed Firestore permissions
    - Use topic-level IAM bindings for Pub/Sub instead of project-level
    - Consider using IAM Conditions to further restrict access
    - Implement Firestore Security Rules for additional data protection
    """
    # Extract event data
    data = cloud_event.data
    bucket_name = data["bucket"]
    file_name = data["name"]

    print(f"Processing file: gs://{bucket_name}/{file_name}")

    # Skip processing for certain file patterns
    if file_name.startswith("processed/") or file_name.endswith("/"):
        print(f"Skipping file: {file_name}")
        return {"status": "skipped", "reason": "excluded path pattern"}

    try:
        # Step 1: Read file from Cloud Storage
        print(f"Step 1: Reading file from GCS...")
        content, metadata = read_file_from_gcs(bucket_name, file_name)
        print(f"File read successfully: {metadata['size']} bytes")

        # Step 2: Process the file content
        print(f"Step 2: Processing file content...")
        processed_data = process_file_content(content, metadata)
        print(f"Processing complete: {processed_data['word_count']} words, "
              f"{processed_data['line_count']} lines")

        # Step 3: Write to Firestore
        print(f"Step 3: Writing to Firestore...")
        doc_id = write_to_firestore(processed_data)

        # Step 4: Publish to Pub/Sub
        print(f"Step 4: Publishing to Pub/Sub...")
        message_id = publish_to_pubsub(processed_data, doc_id)

        # Step 5: Copy to processed bucket (optional)
        if PROCESSED_BUCKET and PROCESSED_BUCKET != bucket_name:
            print(f"Step 5: Copying to processed bucket...")
            try:
                copy_to_processed_bucket(bucket_name, file_name)
            except Exception as copy_error:
                # Non-fatal: log but don't fail the function
                print(f"Warning: Failed to copy to processed bucket: {copy_error}")

        result = {
            "status": "success",
            "file": f"gs://{bucket_name}/{file_name}",
            "firestore_doc_id": doc_id,
            "pubsub_message_id": message_id,
            "processing_timestamp": processed_data["processing_timestamp"],
        }
        print(f"Processing complete: {json.dumps(result)}")
        return result

    except FileNotFoundError as e:
        error_msg = f"File not found: {e}"
        print(f"Error: {error_msg}")
        _record_error(file_name, bucket_name, error_msg)
        return {"status": "error", "message": error_msg}

    except Exception as e:
        error_msg = f"Unexpected error processing {file_name}: {str(e)}"
        print(f"Error: {error_msg}")
        _record_error(file_name, bucket_name, error_msg)
        raise


def _record_error(file_name, bucket_name, error_msg):
    """Record processing errors to Firestore for monitoring."""
    try:
        client = get_firestore_client()
        error_collection = client.collection(f"{FIRESTORE_COLLECTION}_errors")
        error_collection.add({
            "file_name": file_name,
            "bucket": bucket_name,
            "error": error_msg,
            "timestamp": datetime.utcnow().isoformat(),
        })
    except Exception as firestore_error:
        print(f"Failed to record error to Firestore: {firestore_error}")


@functions_framework.http
def process_file_http(request):
    """
    HTTP-triggered version of the file processor.
    Useful for manual triggering or testing.

    Expected JSON body:
    {
        "bucket": "your-bucket-name",
        "name": "path/to/file.txt"
    }

    SECURITY WARNING: Same broad permissions apply as the event-triggered version.
    Additionally, this HTTP endpoint should be secured with authentication
    in production (e.g., requiring IAM authentication or API keys).
    """
    # Parse request
    request_json = request.get_json(silent=True)
    if not request_json:
        return json.dumps({"error": "Request body must be JSON"}), 400

    bucket_name = request_json.get("bucket")
    file_name = request_json.get("name")

    if not bucket_name or not file_name:
        return json.dumps({
            "error": "Missing required fields: 'bucket' and 'name'"
        }), 400

    print(f"HTTP trigger: Processing file gs://{bucket_name}/{file_name}")

    try:
        # Read file
        content, metadata = read_file_from_gcs(bucket_name, file_name)

        # Process
        processed_data = process_file_content(content, metadata)

        # Write to Firestore
        doc_id = write_to_firestore(processed_data)

        # Publish to Pub/Sub
        message_id = publish_to_pubsub(processed_data, doc_id)

        result = {
            "status": "success",
            "file": f"gs://{bucket_name}/{file_name}",
            "firestore_doc_id": doc_id,
            "pubsub_message_id": message_id,
            "processed_data": processed_data,
        }
        return json.dumps(result, default=str), 200

    except FileNotFoundError as e:
        return json.dumps({"error": str(e)}), 404

    except Exception as e:
        return json.dumps({"error": f"Processing failed: {str(e)}"}), 500


